from typing import Dict
from lxml import etree

def get_student_info(
    xml_data: str, username: str, password: str
) -> Dict[str, str] | None:
    try:
        parser = etree.XMLParser(resolve_entities=False, no_network=True, load_dtd=False)
        root = etree.fromstring(xml_data.encode("utf-8"), parser=parser)
    except etree.XMLSyntaxError:
        return None

    query = etree.XPath("//student[username=$uname and password=$pwd]")
    result = query(root, uname=username, pwd=password)

    if result:
        student = result[0]
        info = {}
        for child in student:
            info[child.tag] = child.text if child.text is not None else ""
        return info
    return None

